import{_ as e,o as r,c as d,ag as n}from"./chunks/framework.DXGyWiRo.js";const a="/images/lekt4702.jpg",s="/images/lekt4701.jpg",i="/images/lekt4703.jpg",l="/images/lekt4704.jpg",g=JSON.parse('{"title":"Lektion 47","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion47.md","filePath":"lektionen/lektion47.md"}'),o={name:"lektionen/lektion47.md"};function p(h,t,u,m,c,b){return r(),d("div",null,[...t[0]||(t[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-47" tabindex="-1">Lektion 47 <a class="header-anchor" href="#lektion-47" aria-label="Permalink to &quot;Lektion 47&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>47.1. Der Imperativ (लोट्)</li><li>47.2. Bildung des Imperativs (लोट्) thematischer Präsensstämme <ul><li>47.2.1. Endungen des Imperativ an thematischen Präsensstämmen</li><li>47.2.2. Erste Präsensklasse (भ्वादि)</li><li>47.2.3. Sechste Präsensklasse (तुदादि)</li><li>47.2.4. Vierte Präsensklasse (दिवादि)</li><li>47.2.5. Zehnte Präsensklasse (चुरादि) und Kausative</li><li>47.2.6. Passiv</li></ul></li><li>47.3. Übung</li></ul><h2 id="_47-1-der-imperativ-लोट्" tabindex="-1">47.1. Der Imperativ (लोट्) <a class="header-anchor" href="#_47-1-der-imperativ-लोट्" aria-label="Permalink to &quot;47.1. Der Imperativ (लोट्)&quot;">​</a></h2><p>Der Imperativ (लोट्) bezeichnet</p><ul><li>Befehl (wird auch durch das Gerundivum (कृत्य) ausgedrückt)</li><li>Vorschrift</li><li>Forderung</li><li>Wunsch</li><li>Bitte</li><li>Einladung</li><li>Überlegung</li><li>Frage</li></ul><p>Die genannten Bedeutungen hat er mit dem Optativ (विधिलिङ्) gemeinsam.</p><p>Mit dem Imperativ drückt man auch aus:</p><ul><li>Erlaubnis</li><li>dass eine Handlung an der Zeit ist (wird auch durch das Gerundivum (कृत्य) ausgedrückt)</li><li>Segenswunsch</li></ul><p>Beispiele:</p><blockquote><p>एहि । &quot;Komm!&quot;</p><p>ग्रामं भवानागच्छतु । oder Optativ : ग्रामं भवानगच्छेत् । &quot;Kommen Sie zum Dorf!&quot;</p><p>वेदमध्ययै । oder Optativ: वेदमधीयीय । &quot;Ich möchte den Veda studieren.&quot;</p><p>इच्छामि भुङ्क्तां भवान् । oder Optativ:  इच्छामि भुञ्जीत भवान् । &quot;Ich wünsche, sie mögen essen.&quot;</p><p>किं वेदमध्ययै । oder Optativ: किं वेदमधीयीय । &quot;Sollte ich den Veda studieren?&quot;</p><p>करोतु शस्त्रं भवान् । oder Gerundiv: भवता शस्त्रं कर्तव्यम् । &quot;Machen Sie ein Messer!&quot; ; &quot;Sie dürfen ein Messer machen.&quot; ; &quot;Es ist an der Zeit, dass Sie ein Messer machen.&quot;</p><p>चिरं जीवतु भवान् । &quot;Lange mögen Sie leben!&quot;</p></blockquote><p>Höfliche Befehle werden gerne durch Passiv-Imperative ausgedrückt.</p><p>Beispiele:</p><blockquote><p>भवता प्रविश्यताम् । &quot;Treten Sie bitte ein!&quot;</p><p>निषद्यताम् । &quot;Bitte, setzen Sie sich!&quot;</p></blockquote><p>Im Imperativ des klassischen Sanskrit sind die Formen der 1. Personen alte Konjunktivformen. Der vedische Konjunktiv ist vor allem der Modus, der einen Wunsch ausdrückt: &quot;Wir wollen gehen!&quot; &quot;Lasst uns gehen!&quot;</p><p>Der Imperativ wird vom Präsensstamm gebildet.</p><h2 id="_47-2-bildung-des-imperativs-लोट्-thematischer-prasensstamme" tabindex="-1">47.2. Bildung des Imperativs (लोट्) thematischer Präsensstämme <a class="header-anchor" href="#_47-2-bildung-des-imperativs-लोट्-thematischer-prasensstamme" aria-label="Permalink to &quot;47.2. Bildung des Imperativs (लोट्) thematischer Präsensstämme&quot;">​</a></h2><h3 id="_47-2-1-endungen-des-imperativ-an-thematischen-prasensstammen" tabindex="-1">47.2.1. Endungen des Imperativ an thematischen Präsensstämmen <a class="header-anchor" href="#_47-2-1-endungen-des-imperativ-an-thematischen-prasensstammen" aria-label="Permalink to &quot;47.2.1. Endungen des Imperativ an thematischen Präsensstämmen&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>-āni</td><td>-āma</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>-ø</td><td></td></tr><tr><td>-tāt1</td><td></td><td></td></tr></tbody></table><p>| -ta | -sva | -dhvam | | 3. Person<br> प्रथमः | -tu</p><p>-tāt1</p><p>| -ntu | -tām | -ntām |</p><p>Anm.: 1 Die Endungen der 2. und 3.sg.P können durch -tāt ersetzt werden, wenn ein Segenswunsch ausgedrückt werden soll:</p><blockquote><p>भद्रो भवतात् &quot;Mögest du glücklich sein!&quot; &quot;Er möge glücklich sein!&quot;</p><p>शुभं भवतु oder शुभं भवतात् &quot;Möge es gut sein!&quot; &quot;Alles Gute!&quot;</p></blockquote><h3 id="_47-2-2-erste-prasensklasse-भ्वादि" tabindex="-1">47.2.2. Erste Präsensklasse (भ्वादि) <a class="header-anchor" href="#_47-2-2-erste-prasensklasse-भ्वादि" aria-label="Permalink to &quot;47.2.2. Erste Präsensklasse (भ्वादि)&quot;">​</a></h3><p>भू 1P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>भवानि</td><td>भवाम</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>भव</td><td></td></tr><tr><td>bho + a + ø</td><td>भवत</td><td>&lt;भवस्व&gt;</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>भवतु</td><td>भवन्तु</td></tr></tbody></table></blockquote><h3 id="_47-2-3-sechste-prasensklasse-तुदादि" tabindex="-1">47.2.3. Sechste Präsensklasse (तुदादि) <a class="header-anchor" href="#_47-2-3-sechste-prasensklasse-तुदादि" aria-label="Permalink to &quot;47.2.3. Sechste Präsensklasse (तुदादि)&quot;">​</a></h3><p>विश् 6P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>विशानि</td><td>विशाम</td></tr><tr><td>viś-a + ai</td><td>&lt;विशामहै&gt;</td><td></td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>विश</td><td>विशत</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>विशतु</td><td>विशन्तु</td></tr></tbody></table></blockquote><p><img src="'+a+'" alt=""><br> Abb.: प्रविशत<br> Hanuman Temple, Delhi = हनुमान् मन्दिर, दिल्ली / دہلی<br> [Bildquelle: Carol Mitchell. -- <a href="http://www.flickr.com/photos/webethere/2607777618/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/webethere/2607777618/</a>. -- Zugriff am 2009-01-09. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine Bearbeitung)]</p><h3 id="_47-2-4-vierte-prasensklasse-दिवादि" tabindex="-1">47.2.4. Vierte Präsensklasse (दिवादि) <a class="header-anchor" href="#_47-2-4-vierte-prasensklasse-दिवादि" aria-label="Permalink to &quot;47.2.4. Vierte Präsensklasse (दिवादि)&quot;">​</a></h3><p>नृत् 4P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>नृत्यानि</td><td>नृत्याम</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>नृत्य</td><td>नृत्यत</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>नृत्यतु</td><td>नृत्यन्तु</td></tr></tbody></table></blockquote><p><img src="'+s+'" alt=""><br> Abb.: नृत्यत<br> [Bildquelle: lilPiX. -- <a href="http://www.flickr.com/photos/lilpixie/464706524/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/lilpixie/464706524/</a>. -- Zugriff am 2009-01-09. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><h3 id="_47-2-5-zehnte-prasensklasse-चुरादि-und-kausative" tabindex="-1">47.2.5. Zehnte Präsensklasse (चुरादि) und Kausative <a class="header-anchor" href="#_47-2-5-zehnte-prasensklasse-चुरादि-und-kausative" aria-label="Permalink to &quot;47.2.5. Zehnte Präsensklasse (चुरादि) und Kausative&quot;">​</a></h3><p>चुर् 10U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>चोरयानि</td><td>चोरयाम</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>चोरय</td><td>चोरयत</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>चोरयतु</td><td>चोरयन्तु</td></tr></tbody></table></blockquote><h3 id="_47-2-6-passiv" tabindex="-1">47.2.6. Passiv <a class="header-anchor" href="#_47-2-6-passiv" aria-label="Permalink to &quot;47.2.6. Passiv&quot;">​</a></h3><p>ईक्स् 1Ā</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>ईक्ष्यै</td><td></td></tr><tr><td>īks-ya + ai</td><td>ईक्ष्यामहै</td><td></td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>ईक्ष्यस्व</td><td>ईक्ष्यध्वम्</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>ईक्ष्यताम्</td><td>ईक्ष्यन्ताम्</td></tr></tbody></table></blockquote><h2 id="_47-3-ubung" tabindex="-1">47.3. Übung <a class="header-anchor" href="#_47-3-ubung" aria-label="Permalink to &quot;47.3. Übung&quot;">​</a></h2><p>A) Übersetzen Sie:</p><p>यदि गच्छसि गच्छ त्वम् । अहं न गमिष्यामि ॥१॥</p><p>आर्य प्रेक्षस्व मे परिभवम् ॥२॥</p><p>भो राम यदि मया गन्तव्यं तदैषा कन्यापि मम सहायिनी भवतु ॥३॥</p><p><img src="'+i+'" alt=""><br> Abb.: भो राम यदि मया गन्तवं तदैषा कन्यापि मम सहायिनी भवतु<br> [Bildquelle: said&amp;done. -- <a href="http://www.flickr.com/photos/faraz27989/413649119/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/faraz27989/413649119/</a>. -- Zugriff am 2009-01-10. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>आर्ये तिष्ठ तिष्ठ । न त्वया भेतव्यम् ॥४॥</p><p>प्रसीदत्वार्यः ॥५॥</p><p>आर्ये स्वागतं ते ॥६॥</p><p><img src="'+l+'" alt=""><br> Abb.: आर्ये स्वागतं ते<br> [Bildquelle: imchaudhry. -- <a href="http://www.flickr.com/photos/imranchaudhry/2120997410/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/imranchaudhry/2120997410/</a>. -- Zugriff am 2009-01-10. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>आज्ञापयत्वार्यः किं मया क्रियतामिति ॥७॥</p><p>युद्धाय युज्यस्व नैवं पापमवाप्स्यसि ॥८॥</p><p>प्रश्नः : कस्मात्त्वं भीतः । प्रतिवचनम् : तस्य रामस्य गुणेभ्यः । प्रष्टा : के तस्य गुणा यस्य गृहं प्रविश्याशितव्यमपि नास्ति ॥९॥</p><p>तवैव हस्ते शस्त्रं तिष्ठतु ॥१०॥</p><p>भवति न ते परिभवस्तत्रभवतो रामस्य निवेदयितव्यः ॥११॥</p><p>B.) Übersetzen Sie ins Sanskrit (verwenden Sie den Imperativ):</p><p>1. Ich will erhalten werden.</p><p>2. Er soll zufrieden sein.</p><p>3. Wir wollen rufen.</p><p>4. Ich will mich dir (चतुर्थ्या) beugen.</p><p>5. Diese Tat soll getan werden.</p><p>6. Sie sollen schlafen (Passivkonstruktion).</p><p>7. Mein Sohn strebe nach Reichtum!</p><p>8. Beginnt das Studium!</p><p>9. Gebt (प्र-यम्) den Ahnvätern Reisbällchen!</p><p>10. Sie sollen sich freuen!</p><p>11. Ich will auf die Welt hinabblicken.</p><p>12. Wir wollen nach Benares gehen (पद्).</p><p>13. Sie (pl.) sollen als Opferherren die Götter mit einem Opfer verehren.</p><p>14. Singe ein Loblied!</p><p>15. Söhne sollen mir geboren werden!</p><p>16. Ich will dir mein Haus zeigen.</p><p>17. Gehe von mir weg!</p><p>18. Er soll befreit werden!</p><p>19. Ich will deine Gattin behüten.</p><p>20. Stirb, Feind!</p><p>21. Kämpft!</p><p>22. Sie (pl.) mögen befehlen.</p><p>23. Wir wollen in deinem Haus wohnen.</p><p>24. So soll es geschehen!</p><p>25. Schlage das Pferd!</p><p>26. Sie (pl.) sollen umherirren.</p><p>27. Berauscht euch!</p><p>28. Das Pferd soll die Last ziehen.</p><p>29. Wir wollen die Welten in Ordnung bringen.</p><p>30. Trinke den Trank!</p><p>31. Denke!</p><p>32. Sie (pl.) sollen besiegt werden!</p><p>33. Wir wollen von dir geführt werden.</p><p>34. Es möge zum Glück gereichen (geschehen)! (Segenswunsch)</p>',92)])])}const f=e(o,[["render",p]]);export{g as __pageData,f as default};
